const resp = $.steps.readUrls.response || {};
const values = resp.values || [];
if (values.length < 2) return { urls: [], count: 0 };
const urls = values.slice(1).map((row, i) => ({
  index: i + 1,
  url: row[0] || '',
  name: row[1] || row[0] || 'Site ' + (i + 1)
})).filter(u => u.url.length > 0);
return { urls, count: urls.length };

const urls = $.steps.parseUrls.output.urls || [];
const iterations = $.steps.checkSites.response.iterations || [];
const now = new Date().toISOString();
const results = [];
let downCount = 0;

urls.forEach((u, i) => {
  let status = 'unknown';
  let code = 0;
  let responseTime = 0;
  if (iterations[i] && iterations[i].pingOne) {
    const output = iterations[i].pingOne.output || '';
    const parts = output.trim().split(' ');
    code = parseInt(parts[0] || '0', 10);
    responseTime = parseFloat(parts[1] || '0');
    if (code >= 200 && code < 400) {
      status = 'up';
    } else {
      status = 'down';
      downCount++;
    }
  } else {
    status = 'down';
    downCount++;
  }
  results.push({
    name: u.name,
    url: u.url,
    status: status,
    statusCode: code,
    responseTime: responseTime,
    checkedAt: now
  });
});

const header = ['Name', 'URL', 'Status', 'Code', 'Response Time (s)', 'Checked At'];
const rows = results.map(r => [
  r.name, r.url, r.status, String(r.statusCode),
  String(r.responseTime.toFixed(3)), r.checkedAt
]);

return {
  results, downCount, upCount: results.length - downCount,
  total: results.length, values: [header].concat(rows)
};

const d = $.steps.compileResults.output;
const downSites = d.results.filter(r => r.status === 'down');
const hasDown = downSites.length > 0;

let emailBody = '';
if (hasDown) {
  emailBody = 'DOWNTIME ALERT\n\n';
  emailBody += 'The following sites are DOWN:\n\n';
  downSites.forEach((s, i) => {
    emailBody += (i + 1) + '. ' + s.name + ' (' + s.url + ')\n';
    emailBody += '   Status Code: ' + s.statusCode + '\n';
    emailBody += '   Checked: ' + s.checkedAt + '\n\n';
  });
  emailBody += 'Total: ' + d.total + ' sites monitored, ' + d.downCount + ' down, ' + d.upCount + ' up\n';
}

return { hasDown, downSites, emailBody, emailSubject: 'ALERT: ' + downSites.length + ' site(s) DOWN' };

const d = $.steps.compileResults.output;
const results = d.results || [];
const hasDown = d.downCount > 0;

const blocks = [];
const statusIcon = hasDown ? ':rotating_light:' : ':white_check_mark:';
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Uptime Monitor Report', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: statusIcon + ' *' + d.upCount + '/' + d.total + '* sites up' } });

if (hasDown) {
  const downNames = results.filter(r => r.status === 'down').map(r => r.name).join(', ');
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':x: *DOWN:* ' + downNames } });
}

results.forEach(r => {
  const icon = r.status === 'up' ? ':large_green_circle:' : ':red_circle:';
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: icon + ' *' + r.name + '* — ' + r.statusCode + ' (' + r.responseTime.toFixed(3) + 's)' } });
});

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Results logged to Google Sheets | Powered by One CLI' }] });

const fallback = 'Uptime: ' + d.upCount + '/' + d.total + ' sites up' + (hasDown ? ' - DOWNTIME DETECTED' : '');
return { blocks, fallback };
